import React from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

/**
 * ProtectedRoute Node
 * Ensures the user identity is verified before granting access to 
 * sensitive terminal nodes (Dashboard, Portfolio Generator).
 */
const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  const location = useLocation(); // Captures the path the user intended to visit

  // 1. Terminal Booting/Syncing State
  if (loading) {
    return (
      <div className="min-h-screen bg-[#121212] flex flex-col items-center justify-center font-mono">
        {/* Emerald pulsing ring for a technical look */}
        <div className="relative flex items-center justify-center">
          <div className="absolute animate-ping h-8 w-8 rounded-full bg-emerald-500/20"></div>
          <div className="rounded-full h-8 w-8 border-2 border-emerald-500/20 border-t-emerald-500 animate-spin"></div>
        </div>
        <p className="mt-4 text-[10px] text-emerald-500/50 uppercase tracking-[0.3em] animate-pulse">
          Authenticating_Identity...
        </p>
      </div>
    );
  }

  // 2. Identity Verification Failure
  if (!user) {
    // We use 'replace' to prevent the user from getting stuck in a back-button loop
    // We pass 'state' so we can redirect them back here after they login
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  // 3. Access Granted
  return children;
};

export default ProtectedRoute;
